mapper.select:
select r.id, r.risk_code, r.name, r.description, r.probability, r.impact, r.level, r.status, r.response_strategy, r.task_id, t.name as task_name, r.phase_name, r.owner_id, u.real_name as owner_name, r.identified_at from risk_register r left join sys_user u on u.id = r.owner_id left join project_task t on t.id = r.task_id and t.is_deleted = 0 where r.project_id = #{projectId} and r.is_deleted = 0
and r.level = #{query.level}
and r.status = #{query.status}
and r.owner_id = #{query.ownerId}
and r.task_id = #{query.taskId}
order by r.created_at desc

mapper.insert:
insert into risk_register (
    id, project_id, risk_code, name, description, probability, impact, level, status,
    response_strategy, task_id, phase_name, owner_id, identified_at, closed_at, created_by, created_at, updated_by, updated_at, is_deleted
) values (
    #{id}, #{projectId}, #{riskCode}, #{name}, #{description}, #{probability}, #{impact}, #{level}, #{status},
    #{responseStrategy}, #{taskId}, #{phaseName}, #{ownerId}, #{identifiedAt}, #{closedAt}, #{createdBy}, #{createdAt}, #{updatedBy}, #{updatedAt}, #{deleted}
)

mapper.update:
update risk_register
set is_deleted = 1,
    updated_by = #{updatedBy},
    updated_at = #{updatedAt}
where id = #{id}
  and project_id = #{projectId}
  and is_deleted = 0
